package com.maum.user

import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.never
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import org.assertj.core.api.Assertions.assertThat
import java.time.LocalDateTime
import java.util.Optional

// ───────────────────────────────────────────────
// 도메인 모델 (테스트 파일 내 선언 – 구현 전 Red 단계)
// ───────────────────────────────────────────────

enum class UserStatus { ACTIVE, INACTIVE, DELETED }

data class User(
    val id: Long,
    val nickname: String,
    val status: UserStatus = UserStatus.ACTIVE,
)

data class Follow(
    val id: Long? = null,
    val follower: User,
    val followee: User,
    val createdAt: LocalDateTime = LocalDateTime.now(),
)

// 예외 클래스
class SelfFollowException(message: String) : IllegalArgumentException(message)
class AlreadyFollowingException(message: String) : IllegalStateException(message)
class UserNotFoundException(message: String) : NoSuchElementException(message)
class FollowNotFoundException(message: String) : NoSuchElementException(message)

// Repository 인터페이스
interface UserRepository {
    fun findById(id: Long): Optional<User>
}

interface FollowRepository {
    fun save(follow: Follow): Follow
    fun delete(follow: Follow)
    fun findByFollowerIdAndFolloweeId(followerId: Long, followeeId: Long): Follow?
    fun findAllByFolloweeId(followeeId: Long): List<Follow>
    fun findAllByFollowerId(followerId: Long): List<Follow>
    fun existsByFollowerIdAndFolloweeId(followerId: Long, followeeId: Long): Boolean
}

// 테스트 대상 서비스 인터페이스 (구현 전 Red 단계)
interface UserService {
    fun follow(followerId: Long, followeeId: Long): Follow
    fun unfollow(followerId: Long, followeeId: Long)
    fun getFollowers(userId: Long): List<User>
    fun getFollowings(userId: Long): List<User>
}

// ───────────────────────────────────────────────
// 단위 테스트
// ───────────────────────────────────────────────

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserServiceImpl

    // ── 픽스처 ──────────────────────────────────

    private val follower = User(id = 1L, nickname = "alice")
    private val followee = User(id = 2L, nickname = "bob")

    // ════════════════════════════════════════════
    // follow()
    // ════════════════════════════════════════════

    @Test
    fun `should follow successfully when valid follower and followee are given`() {
        // given
        val expectedFollow = Follow(id = 10L, follower = follower, followee = followee)
        whenever(userRepository.findById(follower.id)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(followee.id)).thenReturn(Optional.of(followee))
        whenever(followRepository.existsByFollowerIdAndFolloweeId(follower.id, followee.id)).thenReturn(false)
        whenever(followRepository.save(any())).thenReturn(expectedFollow)

        // when
        val result = userService.follow(follower.id, followee.id)

        // then
        assertThat(result.follower.id).isEqualTo(follower.id)
        assertThat(result.followee.id).isEqualTo(followee.id)
        verify(followRepository).save(any())
    }

    @Test
    fun `should throw SelfFollowException when follower and followee are the same user`() {
        // given
        val sameUserId = 1L

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(sameUserId, sameUserId)
        }
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw AlreadyFollowingException when follow relationship already exists`() {
        // given
        whenever(userRepository.findById(follower.id)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(followee.id)).thenReturn(Optional.of(followee))
        whenever(followRepository.existsByFollowerIdAndFolloweeId(follower.id, followee.id)).thenReturn(true)

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(follower.id, followee.id)
        }
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw UserNotFoundException when follower does not exist`() {
        // given
        val nonExistentFollowerId = 999L
        whenever(userRepository.findById(nonExistentFollowerId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<UserNotFoundException> {
            userService.follow(nonExistentFollowerId, followee.id)
        }
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw UserNotFoundException when followee does not exist`() {
        // given
        val nonExistentFolloweeId = 999L
        whenever(userRepository.findById(follower.id)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(nonExistentFolloweeId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<UserNotFoundException> {
            userService.follow(follower.id, nonExistentFolloweeId)
        }
        verify(followRepository, never()).save(any())
    }

    // ════════════════════════════════════════════
    // unfollow()
    // ════════════════════════════════════════════

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val existingFollow = Follow(id = 10L, follower = follower, followee = followee)
        whenever(followRepository.findByFollowerIdAndFolloweeId(follower.id, followee.id))
            .thenReturn(existingFollow)

        // when
        userService.unfollow(follower.id, followee.id)

        // then
        verify(followRepository).delete(existingFollow)
    }

    @Test
    fun `should throw FollowNotFoundException when follow relationship does not exist`() {
        // given
        whenever(followRepository.findByFollowerIdAndFolloweeId(follower.id, followee.id))
            .thenReturn(null)

        // when & then
        assertThrows<FollowNotFoundException> {
            userService.unfollow(follower.id, followee.id)
        }
        verify(followRepository, never()).delete(any())
    }

    // ════════════════════════════════════════════
    // getFollowers()
    // ════════════════════════════════════════════

    @Test
    fun `should return follower list when userId has followers`() {
        // given
        val alice = User(id = 3L, nickname = "alice")
        val charlie = User(id = 4L, nickname = "charlie")
        val follows = listOf(
            Follow(id = 1L, follower = alice, followee = followee),
            Follow(id = 2L, follower = charlie, followee = followee),
        )
        whenever(followRepository.findAllByFolloweeId(followee.id)).thenReturn(follows)

        // when
        val result = userService.getFollowers(followee.id)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.id }).containsExactlyInAnyOrder(alice.id, charlie.id)
        verify(followRepository).findAllByFolloweeId(followee.id)
    }

    @Test
    fun `should return empty list when userId has no followers`() {
        // given
        whenever(followRepository.findAllByFolloweeId(followee.id)).thenReturn(emptyList())

        // when
        val result = userService.getFollowers(followee.id)

        // then
        assertThat(result).isEmpty()
        verify(followRepository).findAllByFolloweeId(followee.id)
    }

    // ════════════════════════════════════════════
    // getFollowings()
    // ════════════════════════════════════════════

    @Test
    fun `should return following list when userId follows other users`() {
        // given
        val bob = User(id = 5L, nickname = "bob")
        val dave = User(id = 6L, nickname = "dave")
        val follows = listOf(
            Follow(id = 1L, follower = follower, followee = bob),
            Follow(id = 2L, follower = follower, followee = dave),
        )
        whenever(followRepository.findAllByFollowerId(follower.id)).thenReturn(follows)

        // when
        val result = userService.getFollowings(follower.id)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.id }).containsExactlyInAnyOrder(bob.id, dave.id)
        verify(followRepository).findAllByFollowerId(follower.id)
    }

    @Test
    fun `should return empty list when userId follows nobody`() {
        // given
        whenever(followRepository.findAllByFollowerId(follower.id)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(follower.id)

        // then
        assertThat(result).isEmpty()
        verify(followRepository).findAllByFollowerId(follower.id)
    }
}

// ───────────────────────────────────────────────
// 구현 스텁 (Green 단계에서 실제 구현으로 교체)
// ───────────────────────────────────────────────

class UserServiceImpl(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) : UserService {

    override fun follow(followerId: Long, followeeId: Long): Follow {
        if (followerId == followeeId) {
            throw SelfFollowException("자기 자신을 팔로우할 수 없습니다. userId=$followerId")
        }

        val follower = userRepository.findById(followerId)
            .orElseThrow { UserNotFoundException("팔로워 유저를 찾을 수 없습니다. userId=$followerId") }

        val followee = userRepository.findById(followeeId)
            .orElseThrow { UserNotFoundException("팔로이 유저를 찾을 수 없습니다. userId=$followeeId") }

        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw AlreadyFollowingException("이미 팔로우 중입니다. followerId=$followerId, followeeId=$followeeId")
        }

        return followRepository.save(Follow(follower = follower, followee = followee))
    }

    override fun unfollow(followerId: Long, followeeId: Long) {
        val follow = followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId)
            ?: throw FollowNotFoundException("팔로우 관계가 존재하지 않습니다. followerId=$followerId, followeeId=$followeeId")

        followRepository.delete(follow)
    }

    override fun getFollowers(userId: Long): List<User> {
        return followRepository.findAllByFolloweeId(userId).map { it.follower }
    }

    override fun getFollowings(userId: Long): List<User> {
        return followRepository.findAllByFollowerId(userId).map { it.followee }
    }
}

